     2→
     3→/**
     4→ * Knowledge Hub Material Card
     5→ *
     6→ * Displays a single material with actions, selection, and drag support.
     7→ * WCAG 2.1 AA compliant with keyboard navigation.
     8→ */
     9→
    10→import { useState, useCallback, useRef, KeyboardEvent } from 'react';
    11→import {
    12→  Brain,
    13→  HelpCircle,
    14→  Layers,
    15→  FileText,
    16→  Star,
    17→  MoreVertical,
    18→  GripVertical,
    19→  Check,
    20→  Trash2,
    21→  Archive,
    22→  FolderInput,
    23→  Tag,
    24→  Copy,
    25→  ExternalLink,
    26→} from 'lucide-react';
    27→import { cn } from '@/lib/utils';
    28→import type { ToolType } from '@/types/tools';
    29→
    30→export interface Material {
    31→  id: string;
    32→  title: string;
    33→  type: ToolType;
    34→  createdAt: Date;
    35→  updatedAt: Date;
    36→  tags?: string[];
    37→  collectionId?: string | null;
    38→  isFavorite?: boolean;
    39→  isArchived?: boolean;
    40→  thumbnail?: string;
    41→}
    42→
    43→export interface MaterialCardProps {
    44→  /** Material data */
    45→  material: Material;
    46→  /** Whether the card is selected */
    47→  isSelected?: boolean;
    48→  /** Callback when selection changes */
    49→  onSelect?: (id: string, selected: boolean) => void;
    50→  /** Callback when favorite is toggled */
    51→  onToggleFavorite?: (id: string) => void;
    52→  /** Callback to open material */
    53→  onOpen?: (id: string) => void;
    54→  /** Callback to delete material */
    55→  onDelete?: (id: string) => void;
    56→  /** Callback to archive material */
    57→  onArchive?: (id: string) => void;
    58→  /** Callback to move material */
    59→  onMove?: (id: string) => void;
    60→  /** Callback to add tags */
    61→  onAddTags?: (id: string) => void;
    62→  /** Callback to duplicate material */
    63→  onDuplicate?: (id: string) => void;
    64→  /** Drag start callback for reordering */
    65→  onDragStart?: (id: string) => void;
    66→  /** Drag end callback */
    67→  onDragEnd?: () => void;
    68→  /** Keyboard move callback (for accessibility) */
    69→  onKeyboardMove?: (id: string, direction: 'up' | 'down') => void;
    70→  /** Whether drag is enabled */
    71→  isDraggable?: boolean;
    72→  /** Compact view mode */
    73→  compact?: boolean;
    74→  /** Additional CSS classes */
    75→  className?: string;
    76→}
    77→
    78→const TYPE_ICONS: Record<ToolType, React.ReactNode> = {
    79→  mindmap: <Brain className="w-4 h-4" />,
    80→  quiz: <HelpCircle className="w-4 h-4" />,
    81→  flashcard: <Layers className="w-4 h-4" />,
    82→  summary: <FileText className="w-4 h-4" />,
    83→  demo: <FileText className="w-4 h-4" />,
    84→  diagram: <FileText className="w-4 h-4" />,
    85→  timeline: <FileText className="w-4 h-4" />,
    86→  formula: <FileText className="w-4 h-4" />,
    87→  chart: <FileText className="w-4 h-4" />,
    88→  pdf: <FileText className="w-4 h-4" />,
    89→  webcam: <FileText className="w-4 h-4" />,
    90→  homework: <FileText className="w-4 h-4" />,
    91→  search: <FileText className="w-4 h-4" />,
    92→};
    93→
    94→const TYPE_COLORS: Record<ToolType, string> = {
    95→  mindmap: 'bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400',
    96→  quiz: 'bg-green-100 text-green-600 dark:bg-green-900/30 dark:text-green-400',
    97→  flashcard: 'bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400',
    98→  summary: 'bg-purple-100 text-purple-600 dark:bg-purple-900/30 dark:text-purple-400',
    99→  demo: 'bg-slate-100 text-slate-600 dark:bg-slate-900/30 dark:text-slate-400',
   100→  diagram: 'bg-indigo-100 text-indigo-600 dark:bg-indigo-900/30 dark:text-indigo-400',
   101→  timeline: 'bg-cyan-100 text-cyan-600 dark:bg-cyan-900/30 dark:text-cyan-400',
   102→  formula: 'bg-rose-100 text-rose-600 dark:bg-rose-900/30 dark:text-rose-400',
   103→  chart: 'bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400',
   104→  pdf: 'bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400',
   105→  webcam: 'bg-pink-100 text-pink-600 dark:bg-pink-900/30 dark:text-pink-400',
   106→  homework: 'bg-orange-100 text-orange-600 dark:bg-orange-900/30 dark:text-orange-400',
   107→  search: 'bg-teal-100 text-teal-600 dark:bg-teal-900/30 dark:text-teal-400',
   108→};
   109→
   110→const TYPE_LABELS: Record<ToolType, string> = {
   111→  mindmap: 'Mappa Mentale',
   112→  quiz: 'Quiz',
   113→  flashcard: 'Flashcard',
   114→  summary: 'Riassunto',
   115→  demo: 'Demo',
   116→  diagram: 'Diagramma',
   117→  timeline: 'Timeline',
   118→  formula: 'Formula',
   119→  chart: 'Grafico',
   120→  pdf: 'PDF',
   121→  webcam: 'Immagine',
   122→  homework: 'Compito',
   123→  search: 'Ricerca',
   124→};
   125→
   126→function formatDate(date: Date): string {
   127→  const now = new Date();
   128→  const diffMs = now.getTime() - date.getTime();
   129→  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
   130→
   131→  if (diffDays === 0) return 'Oggi';
   132→  if (diffDays === 1) return 'Ieri';
   133→  if (diffDays < 7) return `${diffDays} giorni fa`;
   134→
   135→  return date.toLocaleDateString('it-IT', {
   136→    day: 'numeric',
   137→    month: 'short',
   138→    year: date.getFullYear() !== now.getFullYear() ? 'numeric' : undefined,
   139→  });
   140→}
   141→
   142→/**
   143→ * Material card component for Knowledge Hub.
   144→ */
   145→export function MaterialCard({
   146→  material,
   147→  isSelected = false,
   148→  onSelect,
   149→  onToggleFavorite,
   150→  onOpen,
   151→  onDelete,
   152→  onArchive,
   153→  onMove,
   154→  onAddTags,
   155→  onDuplicate,
   156→  onDragStart,
   157→  onDragEnd,
   158→  onKeyboardMove,
   159→  isDraggable = false,
   160→  compact = false,
   161→  className,
   162→}: MaterialCardProps) {
   163→  const [isMenuOpen, setIsMenuOpen] = useState(false);
   164→  const [isDragging, setIsDragging] = useState(false);
   165→  const menuRef = useRef<HTMLDivElement>(null);
   166→  const cardRef = useRef<HTMLDivElement>(null);
   167→
   168→  // Handle card click (open)
   169→  const handleClick = useCallback(() => {
   170→    onOpen?.(material.id);
   171→  }, [material.id, onOpen]);
   172→
   173→  // Handle selection
   174→  const handleSelect = useCallback(
   175→    (e: React.MouseEvent) => {
   176→      e.stopPropagation();
   177→      onSelect?.(material.id, !isSelected);
   178→    },
   179→    [material.id, isSelected, onSelect]
   180→  );
   181→
   182→  // Handle favorite toggle
   183→  const handleFavorite = useCallback(
   184→    (e: React.MouseEvent) => {
   185→      e.stopPropagation();
   186→      onToggleFavorite?.(material.id);
   187→    },
   188→    [material.id, onToggleFavorite]
   189→  );
   190→
   191→  // Menu toggle
   192→  const handleMenuToggle = useCallback((e: React.MouseEvent) => {
   193→    e.stopPropagation();
   194→    setIsMenuOpen((prev) => !prev);
   195→  }, []);
   196→
   197→  // Close menu on outside click
   198→  const handleMenuClose = useCallback(() => {
   199→    setIsMenuOpen(false);
   200→  }, []);
   201→
   202→  // Menu action wrapper
   203→  const menuAction = useCallback(
   204→    (action: ((id: string) => void) | undefined) => {
   205→      return (e: React.MouseEvent) => {
   206→        e.stopPropagation();
   207→        action?.(material.id);
   208→        setIsMenuOpen(false);
   209→      };
   210→    },
   211→    [material.id]
   212→  );
   213→
   214→  // Drag handlers
   215→  const handleDragStart = useCallback(
   216→    (e: React.DragEvent) => {
   217→      if (!isDraggable) return;
   218→      setIsDragging(true);
   219→      e.dataTransfer.setData('text/plain', material.id);
   220→      e.dataTransfer.effectAllowed = 'move';
   221→      onDragStart?.(material.id);
   222→    },
   223→    [isDraggable, material.id, onDragStart]
   224→  );
   225→
   226→  const handleDragEnd = useCallback(() => {
   227→    setIsDragging(false);
   228→    onDragEnd?.();
   229→  }, [onDragEnd]);
   230→
   231→  // Keyboard navigation for drag handle (accessibility alternative)
   232→  const handleDragKeyDown = useCallback(
   233→    (e: KeyboardEvent) => {
   234→      if (!isDraggable || !onKeyboardMove) return;
   235→
   236→      if (e.key === 'ArrowUp') {
   237→        e.preventDefault();
   238→        onKeyboardMove(material.id, 'up');
   239→      } else if (e.key === 'ArrowDown') {
   240→        e.preventDefault();
   241→        onKeyboardMove(material.id, 'down');
   242→      }
   243→    },
   244→    [isDraggable, material.id, onKeyboardMove]
   245→  );
   246→
   247→  // Card keyboard handler
   248→  const handleCardKeyDown = useCallback(
   249→    (e: KeyboardEvent) => {
   250→      if (e.key === 'Enter' || e.key === ' ') {
   251→        e.preventDefault();
   252→        handleClick();
   253→      } else if (e.key === 'Delete' && onDelete) {
   254→        e.preventDefault();
   255→        onDelete(material.id);
   256→      }
   257→    },
   258→    [handleClick, material.id, onDelete]
   259→  );
   260→
   261→  return (
   262→    <div
   263→      ref={cardRef}
   264→      onClick={handleClick}
   265→      onKeyDown={handleCardKeyDown}
   266→      draggable={isDraggable}
   267→      onDragStart={handleDragStart}
   268→      onDragEnd={handleDragEnd}
   269→      className={cn(
   270→        'group relative rounded-xl border transition-all duration-200',
   271→        'bg-white dark:bg-slate-800',
   272→        'border-slate-200 dark:border-slate-700',
   273→        'hover:border-accent-themed hover:shadow-md',
   274→        'focus:outline-none focus:ring-2 focus:ring-accent-themed focus:ring-offset-2',
   275→        'cursor-pointer',
   276→        isSelected && 'border-accent-themed bg-accent-themed/5',
   277→        isDragging && 'opacity-50 cursor-grabbing',
   278→        compact ? 'p-3' : 'p-4',
   279→        className
   280→      )}
   281→      role="option"
   282→      tabIndex={0}
   283→      aria-label={`${material.title}, ${TYPE_LABELS[material.type]}${isSelected ? ', selezionato' : ''}`}
   284→      aria-selected={isSelected}
   285→    >
   286→      {/* Drag handle - keyboard accessible */}
   287→      {isDraggable && (
   288→        <button
   289→          className={cn(
   290→            'absolute left-1 top-1/2 -translate-y-1/2',
   291→            'p-1 rounded opacity-0 group-hover:opacity-100',
   292→            'text-slate-400 hover:text-slate-600 dark:hover:text-slate-300',
   293→            'hover:bg-slate-100 dark:hover:bg-slate-700',
   294→            'focus:outline-none focus:ring-2 focus:ring-accent-themed focus:opacity-100',
   295→            'cursor-grab transition-opacity'
   296→          )}
   297→          onKeyDown={handleDragKeyDown}
   298→          aria-label="Trascina per riordinare. Usa frecce su/giù per spostare."
   299→          tabIndex={0}
   300→        >
   301→          <GripVertical className="w-4 h-4" />
   302→        </button>
   303→      )}
   304→
   305→      {/* Selection checkbox */}
   306→      {onSelect && (
   307→        <button
   308→          onClick={handleSelect}
   309→          className={cn(
   310→            'absolute right-2 top-2 p-1 rounded',
   311→            'border-2 transition-all',
   312→            'focus:outline-none focus:ring-2 focus:ring-accent-themed',
   313→            isSelected
   314→              ? 'bg-accent-themed border-accent-themed text-white'
   315→              : 'border-slate-300 dark:border-slate-600 hover:border-accent-themed',
   316→            compact ? 'w-5 h-5' : 'w-6 h-6'
   317→          )}
   318→          aria-label={isSelected ? 'Deseleziona' : 'Seleziona'}
   319→          aria-pressed={isSelected}
   320→        >
   321→          {isSelected && <Check className="w-full h-full" />}
   322→        </button>
   323→      )}
   324→
   325→      {/* Content */}
   326→      <div className={cn('flex gap-3', isDraggable && 'ml-6')}>
   327→        {/* Type icon */}
   328→        <div
   329→          className={cn(
   330→            'flex-shrink-0 p-2 rounded-lg',
   331→            TYPE_COLORS[material.type],
   332→            compact ? 'w-8 h-8' : 'w-10 h-10'
   333→          )}
   334→        >
   335→          {TYPE_ICONS[material.type]}
   336→        </div>
   337→
   338→        {/* Info */}
   339→        <div className="flex-1 min-w-0">
   340→          <h3
   341→            className={cn(
   342→              'font-medium text-slate-900 dark:text-slate-100 truncate',
   343→              compact ? 'text-sm' : 'text-base'
   344→            )}
   345→          >
   346→            {material.title}
   347→          </h3>
   348→
   349→          <div className="flex items-center gap-2 mt-1">
   350→            <span
   351→              className={cn(
   352→                'text-xs px-1.5 py-0.5 rounded',
   353→                TYPE_COLORS[material.type]
   354→              )}
   355→            >
   356→              {TYPE_LABELS[material.type]}
   357→            </span>
   358→            <span className="text-xs text-slate-500">
   359→              {formatDate(material.updatedAt)}
   360→            </span>
   361→          </div>
   362→
   363→          {/* Tags */}
   364→          {!compact && material.tags && material.tags.length > 0 && (
   365→            <div className="flex flex-wrap gap-1 mt-2">
   366→              {material.tags.slice(0, 3).map((tag) => (
   367→                <span
   368→                  key={tag}
   369→                  className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded text-xs bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-400"
   370→                >
   371→                  <Tag className="w-3 h-3" />
   372→                  {tag}
   373→                </span>
   374→              ))}
   375→              {material.tags.length > 3 && (
   376→                <span className="text-xs text-slate-500">
   377→                  +{material.tags.length - 3}
   378→                </span>
   379→              )}
   380→            </div>
   381→          )}
   382→        </div>
   383→
   384→        {/* Actions */}
   385→        <div className="flex items-start gap-1">
   386→          {/* Favorite button */}
   387→          {onToggleFavorite && (
   388→            <button
   389→              onClick={handleFavorite}
   390→              className={cn(
   391→                'p-1.5 rounded-lg transition-colors',
   392→                'focus:outline-none focus:ring-2 focus:ring-accent-themed',
   393→                material.isFavorite
   394→                  ? 'text-amber-500'
   395→                  : 'text-slate-400 hover:text-amber-500'
   396→              )}
   397→              aria-label={
   398→                material.isFavorite
   399→                  ? 'Rimuovi dai preferiti'
   400→                  : 'Aggiungi ai preferiti'
   401→              }
   402→              aria-pressed={material.isFavorite}
   403→            >
   404→              <Star
   405→                className={cn('w-4 h-4', material.isFavorite && 'fill-current')}
   406→              />
   407→            </button>
   408→          )}
   409→
   410→          {/* Context menu */}
   411→          <div ref={menuRef} className="relative">
   412→            <button
   413→              onClick={handleMenuToggle}
   414→              className={cn(
   415→                'p-1.5 rounded-lg transition-colors',
   416→                'text-slate-400 hover:text-slate-600 dark:hover:text-slate-300',
   417→                'hover:bg-slate-100 dark:hover:bg-slate-700',
   418→                'focus:outline-none focus:ring-2 focus:ring-accent-themed'
   419→              )}
   420→              aria-label="Altre azioni"
   421→              aria-expanded={isMenuOpen}
   422→              aria-haspopup="menu"
   423→            >
   424→              <MoreVertical className="w-4 h-4" />
   425→            </button>
   426→
   427→            {isMenuOpen && (
   428→              <>
   429→                {/* Backdrop */}
   430→                <div
   431→                  className="fixed inset-0 z-40"
   432→                  onClick={handleMenuClose}
   433→                  aria-hidden="true"
   434→                />
   435→
   436→                {/* Menu */}
   437→                <div
   438→                  className={cn(
   439→                    'absolute right-0 top-full mt-1 z-50',
   440→                    'min-w-40 py-1 rounded-xl shadow-lg',
   441→                    'bg-white dark:bg-slate-800',
   442→                    'border border-slate-200 dark:border-slate-700'
   443→                  )}
   444→                  role="menu"
   445→                  aria-label="Azioni materiale"
   446→                >
   447→                  {onOpen && (
   448→                    <button
   449→                      onClick={menuAction(onOpen)}
   450→                      className="w-full flex items-center gap-2 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700"
   451→                      role="menuitem"
   452→                    >
   453→                      <ExternalLink className="w-4 h-4" />
   454→                      Apri
   455→                    </button>
   456→                  )}
   457→                  {onDuplicate && (
   458→                    <button
   459→                      onClick={menuAction(onDuplicate)}
   460→                      className="w-full flex items-center gap-2 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700"
   461→                      role="menuitem"
   462→                    >
   463→                      <Copy className="w-4 h-4" />
   464→                      Duplica
   465→                    </button>
   466→                  )}
   467→                  {onMove && (
   468→                    <button
   469→                      onClick={menuAction(onMove)}
   470→                      className="w-full flex items-center gap-2 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700"
   471→                      role="menuitem"
   472→                    >
   473→                      <FolderInput className="w-4 h-4" />
   474→                      Sposta
   475→                    </button>
   476→                  )}
   477→                  {onAddTags && (
   478→                    <button
   479→                      onClick={menuAction(onAddTags)}
   480→                      className="w-full flex items-center gap-2 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700"
   481→                      role="menuitem"
   482→                    >
   483→                      <Tag className="w-4 h-4" />
   484→                      Aggiungi tag
   485→                    </button>
   486→                  )}
   487→                  {onArchive && (
   488→                    <button
   489→                      onClick={menuAction(onArchive)}
   490→                      className="w-full flex items-center gap-2 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700"
   491→                      role="menuitem"
   492→                    >
   493→                      <Archive className="w-4 h-4" />
   494→                      Archivia
   495→                    </button>
   496→                  )}
   497→                  {onDelete && (
   498→                    <>
   499→                      <div className="h-px bg-slate-200 dark:bg-slate-700 my-1" />
   500→                      <button
   501→                        onClick={menuAction(onDelete)}
   502→                        className="w-full flex items-center gap-2 px-3 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20"
   503→                        role="menuitem"
   504→                      >
   505→                        <Trash2 className="w-4 h-4" />
   506→                        Elimina
   507→                      </button>
   508→                    </>
   509→                  )}
   510→                </div>
   511→              </>
   512→            )}
   513→          </div>
   514→        </div>
   515→      </div>
   516→    </div>
   517→  );
   518→}
