     1→// ============================================================================
     2→// API ROUTE: Bulk Material Operations
     3→// POST: Perform bulk operations on multiple materials
     4→// ADR: 0022-knowledge-hub-material-organization.md
     5→// ============================================================================
     6→
     7→import { NextRequest, NextResponse } from 'next/server';
     8→import { cookies } from 'next/headers';
     9→import { z } from 'zod';
    10→import { prisma } from '@/lib/db';
    11→import { logger } from '@/lib/logger';
    12→
    13→// Zod schema for bulk operations
    14→const BulkOperationSchema = z.object({
    15→  materialIds: z.array(z.string().cuid()).min(1).max(100),
    16→  operation: z.enum(['move', 'archive', 'delete', 'restore', 'addTags', 'removeTags', 'setTags']),
    17→  // Optional parameters depending on operation
    18→  collectionId: z.string().cuid().nullable().optional(), // For 'move'
    19→  tagIds: z.array(z.string().cuid()).optional(), // For tag operations
    20→});
    21→
    22→/**
    23→ * POST /api/materials/bulk
    24→ *
    25→ * Perform bulk operations on multiple materials.
    26→ *
    27→ * Operations:
    28→ * - move: Move materials to a collection (collectionId required, null = root)
    29→ * - archive: Set status to 'archived'
    30→ * - delete: Set status to 'deleted'
    31→ * - restore: Set status to 'active'
    32→ * - addTags: Add tags to materials (tagIds required)
    33→ * - removeTags: Remove tags from materials (tagIds required)
    34→ * - setTags: Replace all tags (tagIds required)
    35→ */
    36→export async function POST(request: NextRequest) {
    37→  try {
    38→    // 1. Auth check
    39→    const cookieStore = await cookies();
    40→    const userId = cookieStore.get('convergio-user-id')?.value;
    41→
    42→    if (!userId) {
    43→      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    44→    }
    45→
    46→    // 2. Validate input
    47→    const body = await request.json();
    48→    const validation = BulkOperationSchema.safeParse(body);
    49→
    50→    if (!validation.success) {
    51→      return NextResponse.json(
    52→        {
    53→          error: 'Invalid request',
    54→          details: validation.error.issues.map(e => e.message),
    55→        },
    56→        { status: 400 }
    57→      );
    58→    }
    59→
    60→    const { materialIds, operation, collectionId, tagIds } = validation.data;
    61→
    62→    // 3. Verify all materials belong to user
    63→    const materials = await prisma.material.findMany({
    64→      where: {
    65→        id: { in: materialIds },
    66→        userId,
    67→      },
    68→      select: { id: true },
    69→    });
    70→
    71→    if (materials.length !== materialIds.length) {
    72→      return NextResponse.json(
    73→        { error: 'Some materials not found or not owned by user' },
