   135→    });
   136→  }, [messages, settings.reducedMotion]);
   137→
   138→  // Add greeting on mount or character change
   139→  useEffect(() => {
   140→    const greetingMessage: ConversationMessage = {
   141→      id: 'greeting',
   142→      role: 'assistant',
   143→      content: activeCharacter.greeting,
   144→      timestamp: new Date(),
