   309→  // Toggle voice mode (placeholder for RT-* integration)
   310→  const toggleVoiceMode = useCallback(() => {
   311→    if (onSwitchToVoice) {
   312→      onSwitchToVoice();
   313→    } else {
   314→      setIsVoiceMode((prev) => !prev);
   315→    }
   316→  }, [onSwitchToVoice]);
   317→
   318→  return (
   319→    <div
   320→      className={cn(
   321→        'flex flex-col h-full',
   322→        settings.highContrast ? 'bg-black' : 'bg-white dark:bg-slate-900',
   323→        className
   324→      )}
   325→    >
   326→      {/* Header */}
   327→      <header
   328→        className={cn(
   329→          'flex items-center justify-between px-4 py-3 border-b shrink-0',
   330→          settings.highContrast
   331→            ? 'border-yellow-400 bg-black'
   332→            : 'border-slate-200 dark:border-slate-700'
   333→        )}
   334→      >
   335→        <div className="flex items-center gap-3">
   336→          {/* Character avatar - clickable for switching */}
   337→          <button
   338→            onClick={onSwitchCharacter}
   339→            className={cn(
   340→              'relative group',
   341→              onSwitchCharacter && 'cursor-pointer'
   342→            )}
   343→            disabled={!onSwitchCharacter}
   344→            aria-label={onSwitchCharacter ? 'Cambia personaggio' : undefined}
   345→          >
   346→            <div
   347→              className="w-12 h-12 rounded-full overflow-hidden transition-transform group-hover:scale-105"
   348→              style={{ boxShadow: `0 0 0 3px ${activeCharacter.color}` }}
   349→            >
   350→              <Image
   351→                src={activeCharacter.avatar}
   352→                alt={activeCharacter.name}
   353→                width={48}
   354→                height={48}
   355→                className="w-full h-full object-cover"
   356→              />
   357→            </div>
   358→            {onSwitchCharacter && (
   359→              <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center shadow-sm">
   360→                <ChevronDown className="w-3 h-3" />
   361→              </div>
   362→            )}
   363→          </button>
   364→
   365→          <div>
   366→            <h1
   367→              className={cn(
   368→                'font-semibold text-lg',
   369→                settings.highContrast
   370→                  ? 'text-yellow-400'
   371→                  : 'text-slate-900 dark:text-white'
   372→              )}
   373→            >
   374→              {activeCharacter.name}
   375→            </h1>
   376→            <p
   377→              className={cn(
   378→                'text-xs',
   379→                settings.highContrast ? 'text-gray-400' : 'text-slate-500'
   380→              )}
   381→            >
   382→              {activeCharacter.role === 'learning_coach'
   383→                ? 'Coach di studio'
   384→                : activeCharacter.role === 'buddy'
   385→                  ? 'Compagno di studio'
   386→                  : 'Maestro'}
   387→            </p>
   388→          </div>
   389→        </div>
   390→
   391→        <div className="flex items-center gap-2">
   392→          {/* Voice mode toggle */}
   393→          <Button
   394→            variant="ghost"
   395→            size="sm"
   396→            onClick={toggleVoiceMode}
   397→            className={cn(
   398→              isVoiceMode && 'bg-accent-themed text-white hover:opacity-90'
   399→            )}
   400→            aria-label={isVoiceMode ? 'Disattiva voce' : 'Attiva voce'}
   401→          >
   402→            {isVoiceMode ? (
   403→              <Mic className="w-4 h-4" />
   404→            ) : (
   405→              <MicOff className="w-4 h-4" />
   406→            )}
   407→          </Button>
   408→
   409→          {/* Clear conversation */}
   410→          <Button
   411→            variant="ghost"
   412→            size="sm"
   413→            onClick={clearConversation}
   414→            aria-label="Nuova conversazione"
   415→          >
   416→            <RotateCcw className="w-4 h-4" />
   417→          </Button>
   418→        </div>
   419→      </header>
   420→
   421→      {/* Messages area */}
   422→      <main
   423→        className={cn(
   424→          'flex-1 overflow-y-auto p-4 space-y-4',
   425→          settings.highContrast ? 'bg-black' : ''
   426→        )}
   427→      >
   428→        <AnimatePresence mode="popLayout">
   429→          {messages.map((message) => (
   430→            <motion.div
   431→              key={message.id}
   432→              initial={{ opacity: 0, y: 10 }}
   433→              animate={{ opacity: 1, y: 0 }}
   434→              exit={{ opacity: 0, y: -10 }}
   435→              className={cn(
   436→                'flex gap-3',
   437→                message.role === 'user' ? 'justify-end' : 'justify-start'
   438→              )}
   439→            >
   440→              {/* Avatar for assistant */}
   441→              {message.role === 'assistant' && (
   442→                <div
   443→                  className="w-8 h-8 rounded-full overflow-hidden flex-shrink-0"
   444→                  style={{ boxShadow: `0 0 0 2px ${activeCharacter.color}` }}
   445→                >
   446→                  <Image
   447→                    src={activeCharacter.avatar}
   448→                    alt={activeCharacter.name}
   449→                    width={32}
   450→                    height={32}
   451→                    className="w-full h-full object-cover"
   452→                  />
   453→                </div>
   454→              )}
   455→
   456→              {/* Message content */}
   457→              <div className="flex flex-col gap-2 max-w-[80%]">
   458→                {/* Attachments preview */}
   459→                {message.attachments && message.attachments.length > 0 && (
   460→                  <div className="flex flex-wrap gap-2">
   461→                    {message.attachments.map((att) => (
   462→                      <div
   463→                        key={att.id}
   464→                        className="relative w-20 h-20 rounded-lg overflow-hidden border border-slate-200 dark:border-slate-700"
   465→                      >
   466→                        {att.type === 'image' ? (
   467→                          <Image
   468→                            src={att.url}
   469→                            alt={att.name}
   470→                            fill
   471→                            className="object-cover"
   472→                          />
   473→                        ) : (
   474→                          <div className="w-full h-full flex items-center justify-center bg-slate-100 dark:bg-slate-800">
   475→                            <FileText className="w-6 h-6 text-slate-400" />
   476→                          </div>
   477→                        )}
   478→                      </div>
   479→                    ))}
   480→                  </div>
   481→                )}
   482→
   483→                {/* Message bubble */}
   484→                {message.content && (
   485→                  <div
   486→                    className={cn(
   487→                      'rounded-2xl px-4 py-3',
   488→                      message.role === 'user'
   489→                        ? settings.highContrast
   490→                          ? 'bg-yellow-400 text-black'
   491→                          : 'bg-accent-themed text-white'
   492→                        : settings.highContrast
   493→                          ? 'bg-gray-900 text-white border border-gray-700'
   494→                          : 'bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white',
   495→                      settings.dyslexiaFont && 'tracking-wide'
   496→                    )}
   497→                    style={{ lineHeight: settings.lineSpacing }}
   498→                  >
   499→                    <p className="whitespace-pre-wrap">{message.content}</p>
   500→                  </div>
   501→                )}
   502→
   503→                {/* Tool calls */}
