   508→                    ))}
   509→                  </div>
   510→                )}
   511→              </div>
   512→            </motion.div>
   513→          ))}
   514→        </AnimatePresence>
   515→
   516→        {/* Quick actions (shown after greeting) */}
   517→        {showQuickActions && messages.length === 1 && (
   518→          <motion.div
   519→            initial={{ opacity: 0, y: 20 }}
   520→            animate={{ opacity: 1, y: 0 }}
   521→            className="flex flex-wrap justify-center gap-2 pt-4"
   522→          >
   523→            {QUICK_ACTIONS.map((action) => (
   524→              <Button
   525→                key={action.id}
   526→                variant="outline"
   527→                size="sm"
   528→                onClick={() => handleQuickAction(action.prompt)}
   529→                className="gap-2"
   530→              >
   531→                <action.icon className="w-4 h-4" />
   532→                {action.label}
   533→              </Button>
   534→            ))}
   535→          </motion.div>
   536→        )}
   537→
   538→        {/* Loading indicator */}
   539→        {isLoading && (
   540→          <motion.div
   541→            initial={{ opacity: 0, y: 10 }}
   542→            animate={{ opacity: 1, y: 0 }}
   543→            className="flex gap-3"
   544→          >
   545→            <div
   546→              className="w-8 h-8 rounded-full overflow-hidden flex-shrink-0"
   547→              style={{ boxShadow: `0 0 0 2px ${activeCharacter.color}` }}
   548→            >
   549→              <Image
   550→                src={activeCharacter.avatar}
   551→                alt={activeCharacter.name}
   552→                width={32}
   553→                height={32}
   554→                className="w-full h-full object-cover"
   555→              />
   556→            </div>
   557→            <div
   558→              className={cn(
   559→                'rounded-2xl px-4 py-3 flex items-center gap-2',
   560→                settings.highContrast
   561→                  ? 'bg-gray-900 border border-gray-700'
   562→                  : 'bg-slate-100 dark:bg-slate-800'
   563→              )}
   564→            >
   565→              <Loader2
   566→                className={cn(
   567→                  'w-4 h-4 animate-spin',
   568→                  settings.highContrast ? 'text-yellow-400' : 'text-blue-500'
   569→                )}
   570→              />
   571→              <span
   572→                className={cn(
   573→                  'text-sm',
   574→                  settings.highContrast ? 'text-gray-400' : 'text-slate-500'
   575→                )}
   576→              >
   577→                {activeCharacter.name} sta pensando...
   578→              </span>
   579→            </div>
   580→          </motion.div>
   581→        )}
   582→
   583→        <div ref={messagesEndRef} />
   584→      </main>
   585→
   586→      {/* Attachment preview bar */}
   587→      <AnimatePresence>
   588→        {attachments.length > 0 && (
   589→          <motion.div
   590→            initial={{ height: 0, opacity: 0 }}
   591→            animate={{ height: 'auto', opacity: 1 }}
   592→            exit={{ height: 0, opacity: 0 }}
   593→            className={cn(
   594→              'border-t px-4 py-2',
   595→              settings.highContrast
   596→                ? 'border-yellow-400 bg-black'
   597→                : 'border-slate-200 dark:border-slate-700'
   598→            )}
   599→          >
   600→            <div className="flex gap-2 overflow-x-auto">
   601→              {attachments.map((att) => (
   602→                <div
   603→                  key={att.id}
   604→                  className="relative w-16 h-16 rounded-lg overflow-hidden border border-slate-200 dark:border-slate-700 flex-shrink-0"
   605→                >
   606→                  {att.type === 'image' ? (
   607→                    <Image
   608→                      src={att.url}
   609→                      alt={att.name}
   610→                      fill
   611→                      className="object-cover"
   612→                    />
   613→                  ) : (
   614→                    <div className="w-full h-full flex items-center justify-center bg-slate-100 dark:bg-slate-800">
   615→                      <FileText className="w-4 h-4 text-slate-400" />
   616→                    </div>
   617→                  )}
   618→                  <button
   619→                    onClick={() => removeAttachment(att.id)}
   620→                    className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white rounded-full flex items-center justify-center"
   621→                    aria-label={`Rimuovi ${att.name}`}
   622→                  >
   623→                    <X className="w-3 h-3" />
   624→                  </button>
   625→                </div>
   626→              ))}
   627→            </div>
   628→          </motion.div>
   629→        )}
   630→      </AnimatePresence>
   631→
   632→      {/* Attachment panel */}
   633→      <AnimatePresence>
   634→        {showAttachPanel && (
   635→          <motion.div
   636→            initial={{ height: 0, opacity: 0 }}
   637→            animate={{ height: 'auto', opacity: 1 }}
   638→            exit={{ height: 0, opacity: 0 }}
   639→            className={cn(
   640→              'border-t px-4 py-3',
   641→              settings.highContrast
   642→                ? 'border-yellow-400 bg-gray-900'
   643→                : 'border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800'
   644→            )}
   645→          >
   646→            <div className="flex gap-4 justify-center">
   647→              <button
   648→                onClick={() => cameraInputRef.current?.click()}
   649→                className={cn(
   650→                  'flex flex-col items-center gap-1 p-3 rounded-lg transition-colors',
   651→                  settings.highContrast
   652→                    ? 'hover:bg-yellow-400/20'
   653→                    : 'hover:bg-slate-200 dark:hover:bg-slate-700'
   654→                )}
   655→              >
   656→                <Camera className="w-6 h-6" />
   657→                <span className="text-xs">Fotocamera</span>
   658→              </button>
   659→              <button
   660→                onClick={() => fileInputRef.current?.click()}
   661→                className={cn(
   662→                  'flex flex-col items-center gap-1 p-3 rounded-lg transition-colors',
   663→                  settings.highContrast
   664→                    ? 'hover:bg-yellow-400/20'
   665→                    : 'hover:bg-slate-200 dark:hover:bg-slate-700'
   666→                )}
   667→              >
   668→                <FileText className="w-6 h-6" />
   669→                <span className="text-xs">File</span>
   670→              </button>
   671→            </div>
   672→          </motion.div>
   673→        )}
   674→      </AnimatePresence>
   675→
   676→      {/* Input area */}
   677→      <footer
   678→        className={cn(
   679→          'border-t p-4 shrink-0',
   680→          settings.highContrast
   681→            ? 'border-yellow-400 bg-black'
   682→            : 'border-slate-200 dark:border-slate-700'
   683→        )}
   684→      >
   685→        <form onSubmit={handleSubmit} className="flex gap-2 items-end">
   686→          {/* Attachment button */}
   687→          <Button
   688→            type="button"
   689→            variant="ghost"
   690→            size="sm"
   691→            onClick={() => setShowAttachPanel(!showAttachPanel)}
   692→            className={cn(showAttachPanel && 'bg-slate-100 dark:bg-slate-800')}
   693→            aria-label="Allega file"
   694→          >
   695→            <Paperclip className="w-5 h-5" />
   696→          </Button>
   697→
   698→          {/* Text input */}
   699→          <div className="flex-1 relative">
   700→            <textarea
   701→              ref={inputRef}
   702→              value={input}
   703→              onChange={(e) => setInput(e.target.value)}
   704→              onKeyDown={handleKeyDown}
   705→              placeholder="Scrivi un messaggio o allega un compito..."
   706→              rows={1}
   707→              className={cn(
   708→                'w-full resize-none rounded-xl px-4 py-3 pr-12 focus:outline-none focus:ring-2',
   709→                settings.highContrast
   710→                  ? 'bg-gray-900 text-white border-2 border-yellow-400 focus:ring-yellow-400'
   711→                  : 'bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 focus:ring-blue-500',
   712→                settings.dyslexiaFont && 'tracking-wide'
   713→              )}
   714→              style={{ lineHeight: settings.lineSpacing }}
   715→              disabled={isLoading}
   716→              aria-label="Messaggio"
   717→            />
   718→          </div>
   719→
   720→          {/* Send button */}
   721→          <Button
   722→            type="submit"
   723→            disabled={(!input.trim() && attachments.length === 0) || isLoading}
   724→            style={{
   725→              backgroundColor:
   726→                input.trim() || attachments.length > 0
   727→                  ? activeCharacter.color
   728→                  : undefined,
   729→            }}
   730→            aria-label="Invia messaggio"
   731→          >
   732→            <Send className="w-5 h-5" />
   733→          </Button>
   734→        </form>
   735→
   736→        {/* Hidden file inputs */}
   737→        <input
   738→          ref={fileInputRef}
   739→          type="file"
   740→          accept="image/*,.pdf,.doc,.docx"
   741→          multiple
   742→          onChange={handleFileSelect}
   743→          className="hidden"
   744→        />
   745→        <input
   746→          ref={cameraInputRef}
   747→          type="file"
   748→          accept="image/*"
   749→          capture="environment"
   750→          onChange={handleFileSelect}
   751→          className="hidden"
   752→        />
   753→      </footer>
   754→    </div>
   755→  );
   756→}
   757→
   758→// Utility: Convert file to base64
   759→function fileToBase64(file: File): Promise<string> {
   760→  return new Promise((resolve, reject) => {
   761→    const reader = new FileReader();
   762→    reader.onload = () => resolve(reader.result as string);
   763→    reader.onerror = reject;
   764→    reader.readAsDataURL(file);
   765→  });
   766→}
   767→
   768→export default MaterialiConversation;
   769→

