     1→/**
     2→ * Hook for saved materials (mindmaps, quizzes, flashcards)
     3→ *
     4→ * Replaces localStorage usage with database API.
     5→ * Issue #64: Consolidate localStorage to Database
     6→ */
     7→
     8→import { useState, useEffect, useCallback } from 'react';
     9→import { logger } from '@/lib/logger';
    10→import type { ToolType } from '@/types/tools';
    11→import type { Subject } from '@/types';
    12→
    13→// Material types matching the API
    14→export interface SavedMaterial {
    15→  id: string;
    16→  toolId: string;
    17→  toolType: ToolType;
    18→  title: string;
    19→  content: Record<string, unknown>;
    20→  maestroId?: string;
    21→  sessionId?: string;
    22→  subject?: string;
    23→  preview?: string;
    24→  status: 'active' | 'archived' | 'deleted';
    25→  userRating?: number;
    26→  isBookmarked: boolean;
    27→  viewCount: number;
    28→  createdAt: string;
    29→  updatedAt: string;
    30→}
    31→
    32→// Mindmap-specific type - ADR 0020
    33→export interface SavedMindmap {
    34→  id: string;
    35→  title: string;
    36→  nodes: MindmapNode[];
    37→  markdown?: string; // Pre-generated markdown for rendering
    38→  subject: Subject;
    39→  createdAt: Date;
    40→  maestroId?: string;
    41→}
    42→
    43→interface MindmapNode {
    44→  id: string;
    45→  label: string;
    46→  children?: MindmapNode[];
    47→  icon?: string;
    48→  color?: string;
    49→}
    50→
    51→// Quiz-specific type
    52→export interface SavedQuiz {
    53→  id: string;
    54→  title: string;
    55→  subject: string;
    56→  questions: QuizQuestion[];
    57→  createdAt: Date;
    58→}
    59→
    60→interface QuizQuestion {
    61→  question: string;
    62→  options: string[];
    63→  correctIndex: number;
    64→  explanation?: string;
    65→}
    66→
    67→// Flashcard deck type
    68→export interface SavedFlashcardDeck {
    69→  id: string;
    70→  name: string;
    71→  subject: string;
    72→  cards: FlashcardCard[];
    73→  createdAt: Date;
    74→}
    75→
    76→interface FlashcardCard {
    77→  front: string;
    78→  back: string;
    79→}
    80→
    81→// Homework-specific types
    82→export interface HomeworkStep {
    83→  id: string;
    84→  description: string;
    85→  hints: string[];
    86→  studentNotes: string;
    87→  completed: boolean;
    88→}
    89→
    90→export interface SavedHomework {
    91→  id: string;
    92→  title: string;
    93→  subject: Subject;
    94→  problemType: string;
    95→  photoUrl?: string;
    96→  steps: HomeworkStep[];
    97→  createdAt: Date;
    98→  completedAt?: Date;
    99→}
   100→
   101→// Get default user ID - will be replaced by proper auth
   102→function getUserId(): string {
   103→  // In production, this would come from auth context
   104→  // For now, use a session-based ID
   105→  if (typeof window === 'undefined') return 'default-user';
   106→
   107→  let userId = sessionStorage.getItem('convergio-user-id');
   108→  if (!userId) {
   109→    userId = `user-${crypto.randomUUID()}`;
   110→    sessionStorage.setItem('convergio-user-id', userId);
   111→  }
   112→  return userId;
   113→}
   114→
   115→/**
   116→ * Fetch materials from API
   117→ */
   118→async function fetchMaterials(
   119→  toolType: ToolType,
   120→  userId: string
   121→): Promise<SavedMaterial[]> {
   122→  try {
   123→    const response = await fetch(
   124→      `/api/materials?userId=${userId}&toolType=${toolType}&status=active`
   125→    );
   126→    if (!response.ok) {
   127→      throw new Error(`API error: ${response.status}`);
   128→    }
   129→    const data = await response.json();
   130→    return data.materials || [];
   131→  } catch (error) {
   132→    logger.error('Failed to fetch materials', { error, toolType });
   133→    return [];
   134→  }
   135→}
   136→
   137→/**
   138→ * Save material to API
   139→ */
   140→async function saveMaterialToAPI(
   141→  userId: string,
   142→  toolType: ToolType,
   143→  title: string,
   144→  content: Record<string, unknown>,
   145→  options?: {
   146→    subject?: string;
   147→    maestroId?: string;
   148→    preview?: string;
   149→  }
   150→): Promise<SavedMaterial | null> {
   151→  try {
   152→    const toolId = crypto.randomUUID();
   153→    const response = await fetch('/api/materials', {
   154→      method: 'POST',
   155→      headers: { 'Content-Type': 'application/json' },
   156→      body: JSON.stringify({
   157→        userId,
   158→        toolId,
   159→        toolType,
   160→        title,
   161→        content,
   162→        ...options,
   163→      }),
   164→    });
   165→    if (!response.ok) {
   166→      throw new Error(`API error: ${response.status}`);
   167→    }
   168→    const data = await response.json();
   169→    return data.material;
   170→  } catch (error) {
   171→    logger.error('Failed to save material', { error, toolType, title });
   172→    return null;
   173→  }
   174→}
   175→
   176→/**
   177→ * Delete material via API
   178→ */
   179→async function deleteMaterialFromAPI(toolId: string): Promise<boolean> {
   180→  try {
   181→    const response = await fetch(`/api/materials?toolId=${toolId}`, {
   182→      method: 'DELETE',
   183→    });
   184→    return response.ok;
   185→  } catch (error) {
   186→    logger.error('Failed to delete material', { error, toolId });
   187→    return false;
   188→  }
   189→}
   190→
   191→/**
   192→ * Update material via API
   193→ */
   194→async function updateMaterialInAPI(
   195→  toolId: string,
   196→  content: Record<string, unknown>,
   197→  title?: string
   198→): Promise<boolean> {
   199→  try {
   200→    const response = await fetch('/api/materials', {
   201→      method: 'PATCH',
   202→      headers: { 'Content-Type': 'application/json' },
   203→      body: JSON.stringify({ toolId, content, title }),
   204→    });
   205→    return response.ok;
   206→  } catch (error) {
   207→    logger.error('Failed to update material', { error, toolId });
   208→    return false;
   209→  }
   210→}
   211→
   212→/**
   213→ * Hook for mindmaps
   214→ */
   215→export function useMindmaps() {
   216→  const [mindmaps, setMindmaps] = useState<SavedMindmap[]>([]);
   217→  const [loading, setLoading] = useState(true);
   218→  const userId = getUserId();
   219→
   220→  // Load mindmaps from API - ADR 0020: Extract markdown and handle topic->title compat
   221→  const loadMindmaps = useCallback(async () => {
   222→    setLoading(true);
   223→    const materials = await fetchMaterials('mindmap', userId);
   224→    const mapped: SavedMindmap[] = materials.map((m) => {
   225→      const content = m.content as {
   226→        nodes?: MindmapNode[];
   227→        markdown?: string;
   228→        title?: string;
   229→        topic?: string;
   230→      };
   231→      return {
   232→        id: m.toolId,
   233→        // Prefer title from content, fallback to topic for backward compat
   234→        title: m.title || content.title || content.topic || 'Untitled',
   235→        nodes: content.nodes || [],
   236→        markdown: content.markdown,
   237→        subject: (m.subject || 'general') as Subject,
   238→        createdAt: new Date(m.createdAt),
   239→        maestroId: m.maestroId,
   240→      };
   241→    });
   242→    setMindmaps(mapped);
   243→    setLoading(false);
   244→  }, [userId]);
   245→
   246→  /* eslint-disable react-hooks/set-state-in-effect */
   247→  useEffect(() => {
   248→    loadMindmaps();
   249→  }, [loadMindmaps]);
   250→  /* eslint-enable react-hooks/set-state-in-effect */
   251→
   252→  // Save mindmap - ADR 0020: Include markdown in content
   253→  const saveMindmap = useCallback(
   254→    async (mindmap: Omit<SavedMindmap, 'id' | 'createdAt'>) => {
   255→      const saved = await saveMaterialToAPI(
   256→        userId,
   257→        'mindmap',
   258→        mindmap.title,
   259→        {
   260→          nodes: mindmap.nodes,
   261→          markdown: mindmap.markdown,
   262→          title: mindmap.title, // Store title in content for redundancy
   263→        },
   264→        { subject: mindmap.subject, maestroId: mindmap.maestroId }
   265→      );
   266→      if (saved) {
   267→        await loadMindmaps();
   268→      }
   269→      return saved;
   270→    },
   271→    [userId, loadMindmaps]
   272→  );
   273→
   274→  // Delete mindmap
   275→  const deleteMindmap = useCallback(
   276→    async (id: string) => {
   277→      const success = await deleteMaterialFromAPI(id);
   278→      if (success) {
   279→        setMindmaps((prev) => prev.filter((m) => m.id !== id));
   280→      }
   281→      return success;
   282→    },
   283→    []
   284→  );
   285→
   286→  return { mindmaps, loading, saveMindmap, deleteMindmap, reload: loadMindmaps };
   287→}
   288→
   289→/**
   290→ * Hook for quizzes
   291→ */
   292→export function useQuizzes() {
   293→  const [quizzes, setQuizzes] = useState<SavedQuiz[]>([]);
   294→  const [loading, setLoading] = useState(true);
   295→  const userId = getUserId();
   296→
   297→  const loadQuizzes = useCallback(async () => {
   298→    setLoading(true);
   299→    const materials = await fetchMaterials('quiz', userId);
   300→    const mapped: SavedQuiz[] = materials.map((m) => ({
   301→      id: m.toolId,
   302→      title: m.title,
   303→      subject: m.subject || '',
   304→      questions: (m.content as { questions?: QuizQuestion[] }).questions || [],
   305→      createdAt: new Date(m.createdAt),
   306→    }));
   307→    setQuizzes(mapped);
   308→    setLoading(false);
   309→  }, [userId]);
   310→
   311→  /* eslint-disable react-hooks/set-state-in-effect */
   312→  useEffect(() => {
   313→    loadQuizzes();
   314→  }, [loadQuizzes]);
   315→  /* eslint-enable react-hooks/set-state-in-effect */
   316→
   317→  const saveQuiz = useCallback(
   318→    async (quiz: { title: string; subject: string; questions: QuizQuestion[] }) => {
   319→      const saved = await saveMaterialToAPI(
   320→        userId,
   321→        'quiz',
   322→        quiz.title,
   323→        { questions: quiz.questions },
   324→        { subject: quiz.subject }
   325→      );
   326→      if (saved) {
   327→        await loadQuizzes();
   328→      }
   329→      return saved;
   330→    },
   331→    [userId, loadQuizzes]
   332→  );
   333→
   334→  const deleteQuiz = useCallback(async (id: string) => {
   335→    const success = await deleteMaterialFromAPI(id);
   336→    if (success) {
   337→      setQuizzes((prev) => prev.filter((q) => q.id !== id));
   338→    }
   339→    return success;
   340→  }, []);
   341→
   342→  return { quizzes, loading, saveQuiz, deleteQuiz, reload: loadQuizzes };
   343→}
   344→
   345→/**
   346→ * Hook for flashcard decks
   347→ */
   348→export function useFlashcardDecks() {
   349→  const [decks, setDecks] = useState<SavedFlashcardDeck[]>([]);
   350→  const [loading, setLoading] = useState(true);
   351→  const userId = getUserId();
   352→
   353→  const loadDecks = useCallback(async () => {
   354→    setLoading(true);
   355→    const materials = await fetchMaterials('flashcard', userId);
   356→    const mapped: SavedFlashcardDeck[] = materials.map((m) => ({
   357→      id: m.toolId,
   358→      name: m.title,
   359→      subject: m.subject || '',
   360→      cards: (m.content as { cards?: FlashcardCard[] }).cards || [],
   361→      createdAt: new Date(m.createdAt),
   362→    }));
   363→    setDecks(mapped);
   364→    setLoading(false);
   365→  }, [userId]);
   366→
   367→  /* eslint-disable react-hooks/set-state-in-effect */
   368→  useEffect(() => {
   369→    loadDecks();
   370→  }, [loadDecks]);
   371→  /* eslint-enable react-hooks/set-state-in-effect */
   372→
   373→  const saveDeck = useCallback(
   374→    async (deck: { name: string; subject: string; cards: FlashcardCard[] }) => {
   375→      const saved = await saveMaterialToAPI(
   376→        userId,
   377→        'flashcard',
   378→        deck.name,
   379→        { cards: deck.cards },
   380→        { subject: deck.subject }
   381→      );
   382→      if (saved) {
   383→        await loadDecks();
   384→      }
   385→      return saved;
   386→    },
   387→    [userId, loadDecks]
   388→  );
   389→
   390→  const deleteDeck = useCallback(async (id: string) => {
   391→    const success = await deleteMaterialFromAPI(id);
   392→    if (success) {
   393→      setDecks((prev) => prev.filter((d) => d.id !== id));
   394→    }
   395→    return success;
   396→  }, []);
   397→
   398→  return { decks, loading, saveDeck, deleteDeck, reload: loadDecks };
   399→}
   400→
   401→/**
   402→ * Hook for homework sessions
   403→ */
   404→export function useHomeworkSessions() {
   405→  const [sessions, setSessions] = useState<SavedHomework[]>([]);
   406→  const [loading, setLoading] = useState(true);
   407→  const userId = getUserId();
   408→
   409→  const loadSessions = useCallback(async () => {
   410→    setLoading(true);
   411→    const materials = await fetchMaterials('homework', userId);
   412→    const mapped: SavedHomework[] = materials.map((m) => {
   413→      const content = m.content as {
   414→        steps?: HomeworkStep[];
   415→        problemType?: string;
   416→        photoUrl?: string;
   417→        completedAt?: string;
   418→      };
   419→      return {
   420→        id: m.toolId,
   421→        title: m.title,
   422→        subject: (m.subject || 'mathematics') as Subject,
   423→        problemType: content.problemType || 'Esercizio',
   424→        photoUrl: content.photoUrl,
   425→        steps: content.steps || [],
   426→        createdAt: new Date(m.createdAt),
   427→        completedAt: content.completedAt ? new Date(content.completedAt) : undefined,
   428→      };
   429→    });
   430→    setSessions(mapped);
   431→    setLoading(false);
   432→  }, [userId]);
   433→
   434→  /* eslint-disable react-hooks/set-state-in-effect */
   435→  useEffect(() => {
   436→    loadSessions();
   437→  }, [loadSessions]);
   438→  /* eslint-enable react-hooks/set-state-in-effect */
   439→
   440→  const saveSession = useCallback(
   441→    async (homework: Omit<SavedHomework, 'id' | 'createdAt'>) => {
   442→      const saved = await saveMaterialToAPI(
   443→        userId,
   444→        'homework',
   445→        homework.title,
   446→        {
   447→          steps: homework.steps,
   448→          problemType: homework.problemType,
   449→          photoUrl: homework.photoUrl,
   450→          completedAt: homework.completedAt?.toISOString(),
   451→        },
   452→        { subject: homework.subject }
   453→      );
   454→      if (saved) {
   455→        await loadSessions();
   456→      }
   457→      return saved;
   458→    },
   459→    [userId, loadSessions]
   460→  );
   461→
   462→  const updateSession = useCallback(
   463→    async (homework: SavedHomework) => {
   464→      const success = await updateMaterialInAPI(
   465→        homework.id,
   466→        {
   467→          steps: homework.steps,
   468→          problemType: homework.problemType,
   469→          photoUrl: homework.photoUrl,
   470→          completedAt: homework.completedAt?.toISOString(),
   471→        },
   472→        homework.title
   473→      );
   474→      if (success) {
   475→        setSessions((prev) =>
   476→          prev.map((s) => (s.id === homework.id ? homework : s))
   477→        );
   478→      }
   479→      return success;
   480→    },
   481→    []
   482→  );
   483→
   484→  const deleteSession = useCallback(async (id: string) => {
   485→    const success = await deleteMaterialFromAPI(id);
   486→    if (success) {
   487→      setSessions((prev) => prev.filter((s) => s.id !== id));
   488→    }
   489→    return success;
   490→  }, []);
   491→
   492→  return {
   493→    sessions,
   494→    loading,
   495→    saveSession,
   496→    updateSession,
   497→    deleteSession,
   498→    reload: loadSessions,
   499→  };
   500→}
   501→
   502→// Demo/HTML snippet type (migrated from useHTMLSnippetsStore)
   503→export interface SavedDemo {
   504→  id: string;
   505→  title: string;
   506→  description?: string;
   507→  code: string;
   508→  subject?: string;
   509→  maestroId?: string;
   510→  tags: string[];
   511→  createdAt: Date;
   512→}
   513→
