/**
 * Material Export Utilities
 *
 * Exports materials in various formats (JSON, Markdown, PDF).
 * Supports bulk export and download.
 *
 * ADR: 0022-knowledge-hub-architecture.md
 */

import type { ToolType } from '@/types/tools';

// ============================================================================
// TYPES
// ============================================================================

export type ExportFormat = 'json' | 'markdown' | 'pdf';

export interface ExportableMaterial {
  id: string;
  title: string;
  toolType: ToolType;
  content: string; // JSON string
  subject?: string | null;
  maestroId?: string | null;
  createdAt: Date;
  updatedAt: Date;
}

export interface ExportResult {
  blob: Blob;
  filename: string;
  mimeType: string;
}

export interface BulkExportResult {
  blob: Blob;
  filename: string;
  mimeType: string;
  materialCount: number;
}

// ============================================================================
// SINGLE MATERIAL EXPORT
// ============================================================================

/**
 * Export a single material to the specified format.
 */
export async function exportMaterial(
  material: ExportableMaterial,
  format: ExportFormat
): Promise<ExportResult> {
  switch (format) {
    case 'json':
      return exportAsJson(material);
    case 'markdown':
      return exportAsMarkdown(material);
    case 'pdf':
      return exportAsPdf(material);
    default:
      throw new Error(`Unsupported export format: ${format}`);
  }
}

function exportAsJson(material: ExportableMaterial): ExportResult {
  const data = {
    id: material.id,
    title: material.title,
    type: material.toolType,
    subject: material.subject,
    maestroId: material.maestroId,
    content: safeJsonParse(material.content),
    exportedAt: new Date().toISOString(),
    createdAt: material.createdAt.toISOString(),
    updatedAt: material.updatedAt.toISOString(),
  };

  const json = JSON.stringify(data, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const filename = sanitizeFilename(`${material.title}.json`);

  return { blob, filename, mimeType: 'application/json' };
}

function exportAsMarkdown(material: ExportableMaterial): ExportResult {
  const content = safeJsonParse(material.content);
  const lines: string[] = [];

  // Header
  lines.push(`# ${material.title}`);
  lines.push('');
  lines.push(`**Tipo**: ${formatToolType(material.toolType)}`);
  if (material.subject) {
    lines.push(`**Materia**: ${material.subject}`);
  }
  lines.push(`**Creato**: ${formatDate(material.createdAt)}`);
  lines.push('');
  lines.push('---');
  lines.push('');

  // Content based on type
  lines.push(formatContentAsMarkdown(material.toolType, content));

  const markdown = lines.join('\n');
  const blob = new Blob([markdown], { type: 'text/markdown' });
  const filename = sanitizeFilename(`${material.title}.md`);

  return { blob, filename, mimeType: 'text/markdown' };
}

async function exportAsPdf(material: ExportableMaterial): Promise<ExportResult> {
  // For now, export as markdown and note that PDF requires browser
  // In production, use a library like pdfmake or jspdf
  const markdown = exportAsMarkdown(material);

  // Create a simple HTML wrapper for printing
  const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>${material.title}</title>
  <style>
    body { font-family: system-ui, sans-serif; max-width: 800px; margin: 40px auto; padding: 20px; }
    h1 { color: #333; }
    pre { background: #f5f5f5; padding: 16px; overflow-x: auto; }
    code { font-family: monospace; }
  </style>
</head>
<body>
  <h1>${material.title}</h1>
  <p><strong>Tipo</strong>: ${formatToolType(material.toolType)}</p>
  ${material.subject ? `<p><strong>Materia</strong>: ${material.subject}</p>` : ''}
  <p><strong>Creato</strong>: ${formatDate(material.createdAt)}</p>
  <hr>
  <pre>${await markdown.blob.text()}</pre>
</body>
</html>`;

  const blob = new Blob([html], { type: 'text/html' });
  const filename = sanitizeFilename(`${material.title}.html`);

  return { blob, filename, mimeType: 'text/html' };
}

// ============================================================================
// BULK EXPORT
// ============================================================================

/**
 * Export multiple materials as a single ZIP or JSON file.
 */
export async function exportMaterialsBulk(
  materials: ExportableMaterial[],
  format: ExportFormat = 'json'
): Promise<BulkExportResult> {
  if (materials.length === 0) {
    throw new Error('No materials to export');
  }

  if (materials.length === 1) {
    const result = await exportMaterial(materials[0], format);
    return { ...result, materialCount: 1 };
  }

  // For bulk export, use JSON format with all materials
  const data = {
    exportedAt: new Date().toISOString(),
    count: materials.length,
    materials: materials.map((m) => ({
      id: m.id,
      title: m.title,
      type: m.toolType,
      subject: m.subject,
      maestroId: m.maestroId,
      content: safeJsonParse(m.content),
      createdAt: m.createdAt.toISOString(),
      updatedAt: m.updatedAt.toISOString(),
    })),
  };

  const json = JSON.stringify(data, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const filename = `convergio-export-${formatDateCompact(new Date())}.json`;

  return {
    blob,
    filename,
    mimeType: 'application/json',
    materialCount: materials.length,
  };
}

// ============================================================================
// DOWNLOAD HELPERS
// ============================================================================

/**
 * Trigger a browser download for an export result.
 */
export function downloadExport(result: ExportResult | BulkExportResult): void {
  const url = URL.createObjectURL(result.blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = result.filename;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
}

// ============================================================================
// HELPERS
// ============================================================================

function safeJsonParse(content: string): unknown {
  try {
    return JSON.parse(content);
  } catch {
    return content;
  }
}

function sanitizeFilename(name: string): string {
  return name
    .replace(/[<>:"/\\|?*]/g, '_')
    .replace(/\s+/g, '_')
    .slice(0, 100);
}

function formatToolType(type: ToolType): string {
  const labels: Partial<Record<ToolType, string>> = {
    mindmap: 'Mappa Mentale',
    quiz: 'Quiz',
    flashcard: 'Flashcard',
    summary: 'Riassunto',
    demo: 'Demo Interattiva',
    diagram: 'Diagramma',
    timeline: 'Timeline',
    formula: 'Formula',
    chart: 'Grafico',
    webcam: 'Immagine',
    pdf: 'PDF',
    homework: 'Compiti',
    search: 'Ricerca',
  };
  return labels[type] || type;
}

function formatDate(date: Date): string {
  return date.toLocaleDateString('it-IT', {
    day: '2-digit',
    month: 'long',
    year: 'numeric',
  });
}

function formatDateCompact(date: Date): string {
  return date.toISOString().slice(0, 10);
}

function formatContentAsMarkdown(type: ToolType, content: unknown): string {
  if (!content || typeof content !== 'object') {
    return String(content || '');
  }

  const obj = content as Record<string, unknown>;

  switch (type) {
    case 'mindmap':
      return obj.markdown ? String(obj.markdown) : JSON.stringify(content, null, 2);

    case 'quiz':
      if (!Array.isArray(obj.questions)) return JSON.stringify(content, null, 2);
      return obj.questions
        .map((q: unknown, i: number) => {
          const question = q as Record<string, unknown>;
          const lines = [`## Domanda ${i + 1}`, '', String(question.question)];
          if (Array.isArray(question.options)) {
            lines.push('', ...question.options.map((o, j) => `${j + 1}. ${o}`));
          }
          if (question.explanation) {
            lines.push('', `> ${question.explanation}`);
          }
          return lines.join('\n');
        })
        .join('\n\n');

    case 'flashcard':
      if (!Array.isArray(obj.cards)) return JSON.stringify(content, null, 2);
      return obj.cards
        .map((c: unknown, i: number) => {
          const card = c as Record<string, unknown>;
          return `## Card ${i + 1}\n\n**Domanda**: ${card.front}\n\n**Risposta**: ${card.back}`;
        })
        .join('\n\n---\n\n');

    case 'summary':
      return String(obj.text || obj.content || obj.summary || JSON.stringify(content));

    default:
      return JSON.stringify(content, null, 2);
  }
}

// ============================================================================
// CONVERGIO WEB - DATABASE SCHEMA
// SQLite for local, PostgreSQL for cloud (same schema works for both)
// ============================================================================

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "sqlite"
}

// ============================================================================
// USER & PROFILE
// ============================================================================

model User {
  id        String   @id @default(cuid())
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  profile       Profile?
  settings      Settings?
  progress      Progress?
  sessions          StudySession[]
  flashcards        FlashcardProgress[]
  quizResults       QuizResult[]
  conversations     Conversation[]
  learnings         Learning[]
  pushSubscriptions PushSubscription[]

  // Issue #64: Consolidated localStorage data
  accessibility     AccessibilitySettings?
  onboarding        OnboardingState?
  pomodoroStats     PomodoroStats?
  calendarEvents    CalendarEvent[]
  htmlSnippets      HtmlSnippet[]
  homeworkSessions  HomeworkSession[]
}

model Profile {
  id            String   @id @default(cuid())
  userId        String   @unique
  user          User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  name          String?
  age           Int?
  schoolYear    Int?
  schoolLevel   String   @default("superiore")
  gradeLevel    String?
  learningGoals String   @default("[]")

  // Character preferences (coach and buddy selection)
  preferredCoach String?  // melissa, roberto, chiara, andrea, favij
  preferredBuddy String?  // mario, noemi, enea, bruno, sofia

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt
}

// ============================================================================
// SETTINGS
// ============================================================================

model Settings {
  id            String  @id @default(cuid())
  userId        String  @unique
  user          User    @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Appearance
  theme         String  @default("system")
  language      String  @default("it")
  accentColor   String  @default("blue")

  // Accessibility
  fontSize           String  @default("medium")
  highContrast       Boolean @default(false)
  dyslexiaFont       Boolean @default(false)
  reducedMotion      Boolean @default(false)
  voiceEnabled       Boolean @default(true)
  simplifiedLanguage Boolean @default(false)
  adhdMode           Boolean @default(false)

  // AI Provider
  provider      String  @default("azure")
  model         String  @default("gpt-4o")
  budgetLimit   Float   @default(50.0)
  totalSpent    Float   @default(0.0)

  // Parent Mode Consent (Issue #63)
  parentChatConsentAt DateTime?  // When parent consented to chat with professors

  // Parent Dashboard (Issue #64)
  parentDashboardLastViewed DateTime?  // When parent last viewed the dashboard

  // Azure Cost Configuration
  azureCostConfig String?  // JSON: {token_cost, audio_cost, etc.}

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt
}

// ============================================================================
// PROGRESS & GAMIFICATION
// ============================================================================

model Progress {
  id                String    @id @default(cuid())
  userId            String    @unique
  user              User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  xp                Int       @default(0)
  level             Int       @default(1)

  // Streak
  streakCurrent     Int       @default(0)
  streakLongest     Int       @default(0)
  lastStudyDate     DateTime?

  // Aggregates
  totalStudyMinutes Int       @default(0)
  questionsAsked    Int       @default(0)
  sessionsThisWeek  Int       @default(0)

  // Complex data as JSON
  achievements      String    @default("[]")
  masteries         String    @default("[]")

  createdAt         DateTime  @default(now())
  updatedAt         DateTime  @updatedAt
}

model StudySession {
  id          String    @id @default(cuid())
  userId      String
  user        User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  maestroId   String
  subject     String
  startedAt   DateTime  @default(now())
  endedAt     DateTime?
  duration    Int?
  xpEarned    Int       @default(0)
  questions   Int       @default(0)

  // Student self-evaluation (1-5 stars)
  studentRating    Int?
  studentFeedback  String?

}

// ============================================================================
// TELEMETRY (Usage Analytics & Grafana Integration)
// ============================================================================

model TelemetryEvent {
  id          String   @id @default(cuid())
  eventId     String   @unique // Client-generated event ID for deduplication

  // Event data
  timestamp   DateTime
  category    String   // navigation | education | conversation | maestro | tools | accessibility | error | performance
  action      String   // Specific action (page_view, quiz_started, etc.)
  label       String?  // Additional context (page name, maestro ID, etc.)
  value       Float?   // Numeric value (duration, count, etc.)
  metadata    String?  // JSON for additional key-value pairs

  // Session & user tracking
  sessionId   String
  userId      String?  // Optional, only if authenticated

  createdAt   DateTime @default(now())

  @@index([userId])
  @@index([sessionId])
  @@index([timestamp])
  @@index([category])
  @@index([action])
}

// ============================================================================
// METHOD PROGRESS (Autonomy Tracking - Issue #28)
// ============================================================================

model MethodProgress {
  id        String @id @default(cuid())
  userId    String @unique

  // Skill progress (JSON stored)
  mindMaps       String @default("{}") // MindMapProgress JSON
  flashcards     String @default("{}") // FlashcardProgress JSON
  selfAssessment String @default("{}") // SelfAssessmentProgress JSON
  helpBehavior   String @default("{}") // HelpBehavior JSON
  methodTransfer String @default("{}") // MethodTransfer JSON

  // Events history (JSON array)
  events String @default("[]") // MethodEvent[] JSON

  // Computed scores
  autonomyScore Float @default(0) // 0-1

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  @@index([userId])
  @@index([autonomyScore])
}

// ============================================================================
// MATERIALS (Persisted tool outputs - T-20)
// ============================================================================

model Material {
  id          String   @id @default(cuid())
  userId      String
  toolId      String   @unique // Client-generated tool ID
  toolType    String   // mindmap, quiz, flashcard, demo, etc.
  title       String
  content     String   // JSON string

  // Context
  maestroId   String?
  sessionId   String?
  session     StudySession? @relation(fields: [sessionId], references: [id])
  subject     String?
  preview     String?  // Preview text for lists

  // Migrated from CreatedTool
  topic          String?
  conversationId String?

  // Status
  status      String   @default("active") // active, archived, deleted

  // User interaction (Issue #37 - Archive features)
  userRating   Int?     // 1-5 stars
  isBookmarked Boolean  @default(false)
  viewCount    Int      @default(0)

  // Full-text search (ADR 0022 - Knowledge Hub)
  searchableText String?  // Pre-computed searchable content for Fuse.js

  // Organization (ADR 0022 - Knowledge Hub)
  collectionId String?
  collection   Collection? @relation(fields: [collectionId], references: [id])
  tags         MaterialTag[]

  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

  @@index([userId])
  @@index([toolType])
  @@index([status])
  @@index([sessionId])
  @@index([createdAt])
  @@index([isBookmarked])
  @@index([collectionId])
}

// ============================================================================
// COLLECTIONS (ADR 0022 - Knowledge Hub)
// Folders for organizing materials
// ============================================================================

model Collection {
  id          String       @id @default(cuid())
  userId      String
  name        String
  description String?
  color       String?      // Hex color for folder icon
  icon        String?      // Optional icon name
  parentId    String?      // Nested folders support
  parent      Collection?  @relation("CollectionTree", fields: [parentId], references: [id])
  children    Collection[] @relation("CollectionTree")
  materials   Material[]
  sortOrder   Int          @default(0)
  createdAt   DateTime     @default(now())
  updatedAt   DateTime     @updatedAt

  @@unique([userId, name, parentId])
  @@index([userId])
  @@index([parentId])
}

// ============================================================================
// TAGS (ADR 0022 - Knowledge Hub)
// User-defined tags for materials
// ============================================================================

model Tag {
  id        String        @id @default(cuid())
  userId    String
  name      String
  color     String?       // Hex color for tag badge
  materials MaterialTag[]
  createdAt DateTime      @default(now())
  updatedAt DateTime      @updatedAt

  @@unique([userId, name])
  @@index([userId])
}

model MaterialTag {
  id         String   @id @default(cuid())
  materialId String
  tagId      String
  material   Material @relation(fields: [materialId], references: [id], onDelete: Cascade)
  tag        Tag      @relation(fields: [tagId], references: [id], onDelete: Cascade)
  createdAt  DateTime @default(now())

  @@unique([materialId, tagId])
  @@index([materialId])
  @@index([tagId])
}

// ============================================================================
// PARENT NOTES (Auto-generated session summaries for parents)
// ============================================================================

model ParentNote {
  id          String    @id @default(cuid())
  userId      String
  sessionId   String
  maestroId   String
  subject     String
  duration    Int       // minutes

  // Content
  summary     String    // Brief summary for parents
  highlights  String    // JSON array of achievements
  concerns    String?   // JSON array of concerns (can be empty)
  suggestions String?   // JSON array of suggestions

  // Timestamps
  generatedAt DateTime  @default(now())
  viewedAt    DateTime?

  @@index([userId])
  @@index([sessionId])
  @@index([generatedAt])
}

// ============================================================================
// CREATED TOOLS (Maestro-generated interactive tools - Issue #39, #37)
// DEPRECATED: Use Material table instead. Kept for migration buffer.
// ============================================================================

model CreatedTool {
  id             String   @id @default(cuid())

